const https = require('https');

function verifyToken(token) {
  return new Promise((resolve) => {
    if (!token) { resolve(false); return; }
    const postData = JSON.stringify({ token });
    const req = https.request({ hostname: 'api.katalync.com', port: 443, path: '/webhook/auth-verify', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) } }, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => { try { const d = JSON.parse(Buffer.concat(chunks).toString()); resolve(d.success === true); } catch(e) { resolve(false); } });
    });
    req.on('error', () => resolve(false));
    req.setTimeout(5000, () => { req.destroy(); resolve(false); });
    req.write(postData);
    req.end();
  });
}

const INPUT_MAP = {
  'sku': 'sku-de-vendedor', 'SKU': 'sku-de-vendedor', 'Sku': 'sku-de-vendedor', 'referencia': 'sku-de-vendedor', 'Referencia': 'sku-de-vendedor',
  'ean': 'ean', 'EAN': 'ean', 'ean13': 'ean', 'product-id': 'ean', 'product_id': 'ean',
  'offer-sku': '_offer-sku', 'offer_sku': '_offer-sku',
  'stock': 'quantity', 'Stock': 'quantity', 'quantity': 'quantity', 'Quantity': 'quantity', 'cantidad': 'quantity', 'qty': 'quantity',
  // Native Mirakl API codes (identity mapping)
  'categorias': 'categorias',
  'sku-de-vendedor': 'sku-de-vendedor',
  'nombre-del-articulo': 'nombre-del-articulo',
  'nombre-del-articulo-pt': 'nombre-del-articulo-pt',
  'subtitulo-de-productos': 'subtitulo-de-productos',
  'subtitulo-de-productos-pt': 'subtitulo-de-productos-pt',
  'pais-fabricante': 'pais-fabricante',
  'pais-fabricante-pt': 'pais-fabricante-pt',
  'marcas': 'marcas',
  'descripion-del-producto': 'descripion-del-producto',
  'imagenes-1': 'imagenes-1',
  'imagenes-2': 'imagenes-2',
  'imagenes-3': 'imagenes-3',
  'imagenes-4': 'imagenes-4',
  'colores': 'colores',
  'tipos-de-deportes': 'tipos-de-deportes',
  'nombre-del-fabricante': 'nombre-del-fabricante',
  'nombre-comercial-registrado-del-fabricante': 'nombre-comercial-registrado-del-fabricante',
  'direccion-del-fabricante': 'direccion-del-fabricante',
  'correo-electronico-del-fabricante': 'correo-electronico-del-fabricante',
  'nombre-persona-responsable-en-eu': 'nombre-persona-responsable-en-eu',
  'direccion-de-la-persona-responsable': 'direccion-de-la-persona-responsable',
  'correo-electronico-de-la-persona-responsable': 'correo-electronico-de-la-persona-responsable',
  'foto-etiqueta-del-producto': 'foto-etiqueta-del-producto',
  'manual-de-seguridad-del-producto': 'manual-de-seguridad-del-producto',
  'video': 'video',
  'guia-de-tallas': 'guia-de-tallas',
  'colecciones': 'colecciones',
  'cuidados': 'cuidados'
};

function mapInputRow(row) {
  const mapped = {};
  for (const [key, val] of Object.entries(row)) {
    const apiCode = INPUT_MAP[key] || INPUT_MAP[key.toLowerCase()] || key;
    mapped[apiCode] = val;
  }
  return mapped;
}

const input = $input.first().json.body;
const tokenValid = await verifyToken(input.token);
if (!tokenValid) {
  return [{ json: { status: 'error', message: 'Sesion no valida o expirada. Vuelve a iniciar sesion.', errors: 1, success: 0, errorList: [{ sku: '-', message: 'Token invalido' }], csvBase64: '', csvFilename: '', products: [] } }];
}

const body = input;
const products = body.products || [];
const marketplace = body.marketplace || 'sprinter_es';
const isPT = marketplace === 'sportzone_pt';
const outputFormat = body.outputFormat || '';
const shipmentOrigin = body.shipmentOrigin || 'ES';
const vatPct = body.vatPct || 'ES-21%,PT-23%';

if (!products.length) {
  return [{ json: { success: 0, error: 'No products provided', errors: 0, products: [], errorList: [] } }];
}

const config = { separator: ';', skuCol: 'shop_sku', qtyCol: 'quantity' };
const sep = config.separator;

let successCount = 0;
let errorCount = 0;
const errorList = [];
const previews = [];
const BOM = '﻿';
const csvRows = [config.skuCol + sep + config.qtyCol];
const sprinterOfferRows = [];

for (const p of products) {
  const mapped = mapInputRow(p);
  const sku = mapped['_offer-sku'] || mapped['sku-de-vendedor'] || '';
  const ean = String(mapped['ean'] || '').trim();
  const rawQty = mapped['quantity'] || 0;
  const qty = parseInt(String(rawQty), 10);

  if (!sku) { errorCount++; errorList.push({ sku: '(vacio)', message: isPT ? 'SKU vazio ou nao encontrado' : 'SKU vacio o no encontrado' }); continue; }
  if (isNaN(qty) || qty < 0) { errorCount++; errorList.push({ sku, message: isPT ? 'Quantidade invalida: ' + rawQty : 'Cantidad invalida: ' + rawQty }); continue; }

  csvRows.push(sku + sep + qty);
  successCount++;
  if (previews.length < 6) { previews.push({ sku, quantity: qty }); }

  if (outputFormat === 'sprinter_mirakl') {
    sprinterOfferRows.push({
      'sku': sku,
      'product-id': ean,
      'product-id-type': ean ? 'EAN' : '',
      'description': '',
      'internal-description': '',
      'price': '',
      'price-additional-info': '',
      'quantity': String(qty),
      'min-quantity-alert': '',
      'state': '',
      'available-start-date': '',
      'available-end-date': '',
      'logistic-class': '',
      'favorite-rank': '',
      'discount-price': '',
      'discount-start-date': '',
      'discount-end-date': '',
      'discount-ranges': '',
      'leadtime-to-ship': '',
      'update-delete': '',
      'price[channel=INIT]': '',
      'discount-price[channel=INIT]': '',
      'discount-start-date[channel=INIT]': '',
      'discount-end-date[channel=INIT]': '',
      'discount-ranges[channel=INIT]': '',
      'shipment-origin': shipmentOrigin,
      'vat-percentage': vatPct
    });
  }
}

const csvContent = BOM + csvRows.join('\n');
const csvBase64 = Buffer.from(csvContent, 'utf-8').toString('base64');
const timestamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const csvFilename = 'stock_' + marketplace + '_' + timestamp + '.csv';
const msg = isPT ? successCount + ' produtos de stock processados com sucesso' : successCount + ' productos de stock procesados correctamente';

const response = { success: successCount, errors: errorCount, message: msg, products: previews, errorList: errorList, csvBase64: csvBase64, csvFilename: csvFilename };

if (outputFormat === 'sprinter_mirakl' && sprinterOfferRows.length > 0) {
  response.sprinterOfferRows = sprinterOfferRows;
  response.offersFilename = 'stock_sprinter_' + new Date().toISOString().slice(0,10) + '.xlsx';
}

return [{ json: response }];

